class Solution:
    def bestTeamScore(self, scores, ages):
        n = len(scores)
        best = 0
        for mask in range(1, 1 << n):
            selected = [i for i in range(n) if mask & (1 << i)]
            ok = True
            for a_idx in range(len(selected)):
                for b_idx in range(len(selected)):
                    i, j = selected[a_idx], selected[b_idx]
                    if ages[i] < ages[j] and scores[i] > scores[j]:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                best = max(best, sum(scores[i] for i in selected))
        return best

